  ('promotion-6e2f88c7-moex-00115', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於公法上法律關係得以契約設定、變更或消滅之規定，下列敘述何者錯誤？', '["得以契約標的具有公法性質，作為行政契約判斷標準之一", "契約之內容以執行公法法規為目的，屬公法契約", "行政機關原則上得以行政處分作為行使契約上權利之手段", "二個以上之公權力主體得締結行政契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00116', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於行政罰之處罰對象，下列敘述何者錯誤？', '["多數人故意共同實施因身分或其他特定關係成立之違反行政法上義務行為，其無此身分或特定 關係者，不受處罰", "地方行政機關得為裁罰對象", "私法人之董事因執行其職務之行為，致使私法人違反行政法上義務應受處罰者，該董事如有重 大過失，原則上應並受同一規定罰鍰之處罰", "多數人故意共同實施違反行政法上義務之行為，應依其行為情節之輕重，分別處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00117', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '依行政執行法與司法實務見解，關於行政執行聲明異議之敘述，下列何者正確？', '["對具行政處分性質之執行命令不服，經聲明異議程序，仍有不服時，聲明異議人可直接提起撤 銷訴訟", "對具行政處分性質之執行命令不服，得擇一聲明異議或提起訴願", "對具行政處分性質之執行命令不服，經聲明異議程序仍有不服者，應依法踐行訴願程序", "行政執行貴在效率，聲明異議為特別之救濟程序，即不得再循一般爭訟程序請求救濟 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00118', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於行政程序法之迴避，下列敘述何者錯誤？', '["公務員在行政程序中發現事件當事人曾為三等親內之姻親，應自行迴避", "公務員在稅務事件中發現當事人為其所厭惡之國小導師，自認執行職務有偏頗之虞，向所屬機 關自請迴避，機關認為不符應自行迴避事由，應否准之", "當事人有具體事證，足認承辦公務員執行職務有偏頗之虞，得向公務員所屬機關申請迴避", "公務員所屬機關之長官於公務員有應自行迴避之事由而不迴避，而未經當事人申請迴避時，應 依職權命其迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00119', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '下列何者得提起訴願救濟？', '["公務人員對公務人員保障暨培訓委員會之復審決定不服", "會計師不服懲戒處分，向財政部會計師覆審委員會聲請覆審，對於該覆審決議不服", "義務人對具有行政處分性質之執行命令不服，依行政執行法聲明異議經上級機關駁回異議", "納稅義務人對於課稅處分不服，依稅捐稽徵法申請復查，對於復查決定不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00120', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於訴願當事人適格之敘述，下列何者錯誤？', '["訴願人具有訴願權能，得以自己名義提起訴願者，具有當事人適格", "因行政處分遭受生活上不便利者，皆具有訴願當事人適格", "行政處分相對人以外之第三人亦可能具訴願當事人適格", "訴願當事人是否適格，受理訴願機關應依職權調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
  ('promotion-6e2f88c7-moex-00121', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '依行政訴訟法規定，關於訴訟標的對於共同訴訟之各人，必須合一確定者，下列敘述何者錯誤？', '["他造對於共同訴訟人中之一人之行為，其效力及於全體", "共同訴訟人中之一人，生有訴訟當然停止之原因者，其效力及於全體", "共同訴訟人中之一人之行為有利益於共同訴訟人者，其效力及於全體", "共同訴訟人中之一人所為不利益於共同訴訟人之行為，其效力僅及於該人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL),
