  ('promotion-6e2f88c7-moex-00123', 'promotion-6e2f88c7', 'promotion-6e2f88c7-moex-112-3082b5f1', 'sub-promotion-6e2f88c7-04', NULL, 'single_choice', '關於國家賠償，下列敘述何者錯誤？', '["公共設施包括非由國家設置，但事實上由其管理且直接供公共使用之設施", "公共設施委託民間團體管理時，因管理欠缺致人民身體受損害者，國家應負損害賠償責任", "國家賠償請求權，自損害發生時起，因2年間不行使而消滅", "賠償義務機關得於一定金額限度內，與請求權人逕行協議決定賠償金額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:56+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "125", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "法制"}'::jsonb, NULL)
